// --- TIPOS ---
interface PrinterInfo {
  id: string;
  type: string;
  trays: string;
  installDate: string;
  serial: string;
  location?: string;
  warrantyDate?: string; // fecha fin de garantía/contrato mantenimiento
}

interface AuditLog {
  id: string;
  timestamp: string;
  user: string;
  action: string;
  detail: string;
  entityId?: string;
  meta?: Record<string, any>; // extra structured data for detail panel
}

interface Client {
  id: number;
  name: string;
  province: string;
  ruc_id: string;
  contact: string;
  client_code: string;
  alt_codes?: string[];
  salesperson: string;
  printers?: PrinterInfo[];
  notes?: string; // notas libres CRM
}

interface StockEntry {
  id: string;
  date: string;
  size: string;
  quantity: number;
  batch_number: string;
  expiry_date: string;
  unit_cost: number;
  supplier_invoice: string;
  purchase_order?: string; // Ej: FJ-2001
  notes: string;
  film_type?: 'DIHT' | 'DIHL' | 'DIML';
  is_opening?: boolean;
}

interface StockMinimum {
  size: string;
  minimum: number;
}

interface ConsumptionRecord {
  id: number;
  client_id: number;
  order_date: string;
  invoice_number?: string;
  quantity: number;
  size: string;
  batch_number: string;
  expiry_date: string;
  unit_cost?: number;
  sale_price?: number;   // precio de venta al cliente (columna PRECIO del CSV)
  film_type?: 'DIHT' | 'DIHL' | string;
  is_return?: boolean;
  adapted_to?: string;
  adapted_ratio?: number;
  // Nota de Crédito
  nc_type?: 'devolucion' | 'anulacion'; // tipo de NC
  nc_number?: string;                    // número de la NC
  nc_invoice_ref?: string;               // factura original que anula
  nc_new_invoice?: string;               // nueva factura (para anulación+refacturación)
  nc_reason?: string;                    // motivo
  categoria?: string;                    // linea o categoria del producto
}

